import { Box, Container, Spacer, VStack ,Checkbox, Input } from "@chakra-ui/react"
import { useState } from "react"

export const IncompleteTodos = (props) => {
    const { incompleteTodos, onClickComplete, onClickDelete } = props;

    const [isClick, setIsClick] = useState(false);
    const [inputCardTitle, setInputCardTitle] = useState();

    const handleClick = () => {
      // 真偽値をfalseからtrueに変更
      setIsClick(true);
      console.log(isClick);
    }

    const handleChange = (e) => {
      console.log(inputCardTitle);
      setInputCardTitle(e.target.value);
    }

    const handleSubmit = (e) => {
      e.preventDefault();
      setIsClick(false);
    }

    return (
    <div>
            <VStack>
            <Container maxW='xl' bg='white.600' color='gray'>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((inputCardTitle, index) => (
          <li key={inputCardTitle}>
            <Box display="flex" p={2}>
            <Checkbox onChange={() => onClickComplete(index)}></Checkbox>

            <Spacer />
            <Box px={2}>





            </Box>
            <button onClick={() => onClickDelete(index)}>削除</button>

            </Box>
          </li>
            )
        )}
        </ul>
        </Container>
        </VStack>
    </div>
    )
}
